mapper.select:
SELECT i.id, i.site_id AS siteId, s.site_name AS siteName, s.site_code AS siteCode, i.external_id AS externalId, i.title, i.url, i.author, i.recommendation_count AS recommendationCount, i.unrecommendation_count AS unrecommendationCount, i.view_count AS viewCount, i.comment_count AS commentCount, i.price, i.deal_category AS dealCategory, i.thumbnail_url AS thumbnailUrl, i.notified, i.notified_at AS notifiedAt, i.scraped_at AS scrapedAt, i.created_at AS createdAt FROM tb_hot_deal_item i INNER JOIN tb_hot_deal_site s ON i.site_id = s.id
AND i.site_id = #{siteId}
AND i.title LIKE CONCAT('%', #{title}, '%')
AND i.notified = #{notified}
AND i.deal_category = #{dealCategory}
AND i.scraped_at >= #{scrapedAtFromUtc}
AND i.scraped_at < #{scrapedAtToUtcExclusive}
